            try:
                ctx_a = browser.new_context(viewport=viewport)
                ctx_b = browser.new_context(viewport=viewport)
                page_a = ctx_a.new_page()
                page_b = ctx_b.new_page()

                page_a.goto(BASE_URL + "/", wait_until="networkidle", timeout=60000)
                page_b.goto(BASE_URL + "/", wait_until="networkidle", timeout=60000)

                for page in (page_a, page_b):
                    page.wait_for_selector('[data-testid="canvas-viewport"]', timeout=30000)
                    page.wait_for_selector('[data-testid="avatar-bar"]', timeout=30000)

                # Verify initial state on user A.
                initial_following = page_a.get_attribute(
                    '[data-testid="canvas-viewport"]', "data-following"
                )
                assert initial_following == "", (
                    f"Initial data-following on user A must be empty, got {initial_following!r}"
                )
                initial_camera = page_a.get_attribute(
                    '[data-testid="canvas-viewport"]', "data-camera"
                )
                assert json.loads(initial_camera) == {"x": 0, "y": 0}, (
                    f"Initial data-camera must be (0,0); got {initial_camera!r}"
                )

                # Move user B's cursor inside the canvas to the known coordinate.
                canvas_b = page_b.locator('[data-testid="canvas-viewport"]')
                box_b = canvas_b.bounding_box()
                assert box_b is not None, "canvas-viewport has no bounding box on user B."
                # Use page.mouse.move which produces real pointer events on the canvas.
                page_b.mouse.move(
