                # so we don't depend on the canvas's actual on-screen size.
                page_b.evaluate(
                    """
                    ({x, y}) => {
                        const el = document.querySelector('[data-testid="canvas-viewport"]');
                        const rect = el.getBoundingClientRect();
                        const ev = new PointerEvent('pointermove', {
                            bubbles: true,
                            cancelable: true,
                            clientX: rect.left + x,
                            clientY: rect.top + y,
                            pointerType: 'mouse',
                        });
                        el.dispatchEvent(ev);
                    }
                    """,
                    target_cursor,
                )

